import React, { useState } from 'react';
import { useNavigate } from 'react-router-dom';
import axios from 'axios';
import './CustomerDashboard.css';

const API_URL = process.env.REACT_APP_API_URL || 'http://localhost:5000/api';

const CreateReturn = () => {
  const navigate = useNavigate();
  const [loading, setLoading] = useState(false);
  const [formData, setFormData] = useState({
    transactionId: '',
    riceType: 'Sinandomeng',
    quantityKg: '',
    amountPaid: '',
    returnReason: ''
  });
  const [receipt, setReceipt] = useState(null);

  const handleChange = (e) => {
    setFormData({
      ...formData,
      [e.target.name]: e.target.value
    });
  };

  const handleFileChange = (e) => {
    setReceipt(e.target.files[0]);
  };

  const handleSubmit = async (e) => {
    e.preventDefault();
    setLoading(true);

    const data = new FormData();
    data.append('receipt', receipt);
    Object.keys(formData).forEach(key => {
      data.append(key, formData[key]);
    });

    try {
      await axios.post(`${API_URL}/returns`, data, {
        headers: { 'Content-Type': 'multipart/form-data' }
      });
      navigate('/customer/returns');
    } catch (error) {
      console.error('Error creating return:', error);
      alert('Failed to create return request');
    } finally {
      setLoading(false);
    }
  };

  return (
    <div className="main-content" style={{ marginLeft: 0, padding: '2rem' }}>
      <div style={{ maxWidth: '600px', margin: '0 auto' }}>
        <h1 style={{ fontSize: '1.75rem', fontWeight: 600, marginBottom: '2rem', color: '#212529' }}>
          Request a Return
        </h1>
        
        <form onSubmit={handleSubmit} style={{ background: 'white', border: '1px solid #dee2e6', borderRadius: '8px', padding: '2rem' }}>
          <div style={{ marginBottom: '1.5rem' }}>
            <label style={{ display: 'block', marginBottom: '0.5rem', fontWeight: 500, color: '#495057' }}>
              Transaction ID *
            </label>
            <input
              type="text"
              name="transactionId"
              value={formData.transactionId}
              onChange={handleChange}
              required
              style={{
                width: '100%',
                padding: '0.75rem',
                border: '1px solid #ced4da',
                borderRadius: '4px',
                fontSize: '0.95rem'
              }}
              placeholder="e.g., TXN-123456"
            />
          </div>

          <div style={{ marginBottom: '1.5rem' }}>
            <label style={{ display: 'block', marginBottom: '0.5rem', fontWeight: 500, color: '#495057' }}>
              Rice Type *
            </label>
            <select
              name="riceType"
              value={formData.riceType}
              onChange={handleChange}
              required
              style={{
                width: '100%',
                padding: '0.75rem',
                border: '1px solid #ced4da',
                borderRadius: '4px',
                fontSize: '0.95rem',
                background: 'white'
              }}
            >
              <option value="Sinandomeng">Sinandomeng</option>
              <option value="Dinorado">Dinorado</option>
            </select>
          </div>

          <div style={{ display: 'grid', gridTemplateColumns: '1fr 1fr', gap: '1rem', marginBottom: '1.5rem' }}>
            <div>
              <label style={{ display: 'block', marginBottom: '0.5rem', fontWeight: 500, color: '#495057' }}>
                Quantity (kg) *
              </label>
              <input
                type="number"
                name="quantityKg"
                value={formData.quantityKg}
                onChange={handleChange}
                required
                step="0.1"
                min="0.1"
                style={{
                  width: '100%',
                  padding: '0.75rem',
                  border: '1px solid #ced4da',
                  borderRadius: '4px',
                  fontSize: '0.95rem'
                }}
              />
            </div>
            <div>
              <label style={{ display: 'block', marginBottom: '0.5rem', fontWeight: 500, color: '#495057' }}>
                Amount Paid (₱) *
              </label>
              <input
                type="number"
                name="amountPaid"
                value={formData.amountPaid}
                onChange={handleChange}
                required
                step="0.01"
                min="0"
                style={{
                  width: '100%',
                  padding: '0.75rem',
                  border: '1px solid #ced4da',
                  borderRadius: '4px',
                  fontSize: '0.95rem'
                }}
              />
            </div>
          </div>

          <div style={{ marginBottom: '1.5rem' }}>
            <label style={{ display: 'block', marginBottom: '0.5rem', fontWeight: 500, color: '#495057' }}>
              Return Reason *
            </label>
            <textarea
              name="returnReason"
              value={formData.returnReason}
              onChange={handleChange}
              required
              rows="3"
              style={{
                width: '100%',
                padding: '0.75rem',
                border: '1px solid #ced4da',
                borderRadius: '4px',
                fontSize: '0.95rem',
                resize: 'vertical'
              }}
              placeholder="Please explain why you're returning this item..."
            />
          </div>

          <div style={{ marginBottom: '2rem' }}>
            <label style={{ display: 'block', marginBottom: '0.5rem', fontWeight: 500, color: '#495057' }}>
              Receipt Image *
            </label>
            <input
              type="file"
              onChange={handleFileChange}
              accept="image/*"
              required
              style={{
                width: '100%',
                padding: '0.75rem',
                border: '1px solid #ced4da',
                borderRadius: '4px',
                fontSize: '0.95rem'
              }}
            />
            <p style={{ fontSize: '0.8rem', color: '#6c757d', marginTop: '0.25rem' }}>
              Upload a clear photo of your receipt
            </p>
          </div>

          <div style={{ display: 'flex', justifyContent: 'flex-end', gap: '1rem' }}>
            <button
              type="button"
              onClick={() => navigate('/customer/returns')}
              style={{
                padding: '0.75rem 1.5rem',
                background: 'white',
                border: '1px solid #ced4da',
                borderRadius: '4px',
                fontSize: '0.95rem',
                color: '#495057',
                cursor: 'pointer'
              }}
            >
              Cancel
            </button>
            <button
              type="submit"
              disabled={loading}
              style={{
                padding: '0.75rem 1.5rem',
                background: '#212529',
                border: 'none',
                borderRadius: '4px',
                fontSize: '0.95rem',
                color: 'white',
                cursor: loading ? 'not-allowed' : 'pointer',
                opacity: loading ? 0.6 : 1
              }}
            >
              {loading ? 'Submitting...' : 'Submit Return Request'}
            </button>
          </div>
        </form>
      </div>
    </div>
  );
};

export default CreateReturn;
